record.field:
sql = """
CREATE OR REPLACE FUNCTION user_websites_flush_view_counters(updates JSONB) RETURNS VOID AS $$
DECLARE
    update_record RECORD;
BEGIN
    FOR update_record IN SELECT * FROM jsonb_to_recordset(updates) AS (inc INTEGER, pid INTEGER)
    LOOP
        UPDATE website_page SET view_count = COALESCE(view_count, 0) + update_record.inc WHERE id = update_record.pid;
    END LOOP;
END;
$$ LANGUAGE plpgsql;
"""
env.cr.execute(sql)
